import React, { useEffect, useMemo, useState } from 'react'
import { cultivationLogService, seasonService } from '../../services/api'
import '../../styles/worker/worker-feed-logs.css'

const ACTION_OPTIONS = [
  { label: 'Thay nÆ°á»›c', value: 'water_change' },
  { label: 'Siphon Ä‘Ã¡y', value: 'siphon_bottom' },
  { label: 'DÃ¹ng thuá»‘c', value: 'medication' },
  { label: 'Bá»• sung vi sinh', value: 'probiotics' },
  { label: 'Xá»­ lÃ½ mÃ´i trÆ°á»ng', value: 'env_treatment' },
]

const emptyForm = {
  seasonId: '',
  actionType: '',
  description: '',
  logDate: '',
}

const formatDate = (value) => {
  if (!value) return '-'
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return '-'
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    timeZone: 'Asia/Ho_Chi_Minh',
  }).format(date)
}

const WorkerCultivationLogs = () => {
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState('')
  const [seasons, setSeasons] = useState([])
  const [logs, setLogs] = useState([])
  const [form, setForm] = useState(emptyForm)

  const selectedSeasonId = form.seasonId

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        setLoading(true)
        const seasonsRes = await seasonService.getAllSeasons()
        const seasonDataRaw = seasonsRes?.data?.data || []

        const allowedSeasons = seasonDataRaw.filter((season) => {
          const status = String(season.status || '').toUpperCase()
          return status === 'RUNNING' || status === 'ACTIVE' || status === 'OPEN'
        })

        setSeasons(allowedSeasons.length > 0 ? allowedSeasons : seasonDataRaw)

        if (seasonDataRaw.length > 0) {
          setForm((prev) => ({ ...prev, seasonId: String(seasonDataRaw[0].season_id) }))
        }

        setError('')
      } catch (loadError) {
        setError(loadError?.response?.data?.message || 'KhÃ´ng táº£i Ä‘Æ°á»£c dá»¯ liá»‡u mÃ¹a vá»¥')
      } finally {
        setLoading(false)
      }
    }

    loadInitialData()
  }, [])

  useEffect(() => {
    const loadLogs = async () => {
      if (!selectedSeasonId) {
        setLogs([])
        return
      }

      try {
        const logsRes = await cultivationLogService.getBySeasonId(selectedSeasonId)
        setLogs(logsRes?.data?.data || [])
      } catch (loadError) {
        setLogs([])
        setError(loadError?.response?.data?.message || 'KhÃ´ng táº£i Ä‘Æ°á»£c nháº­t kÃ½ canh tÃ¡c')
      }
    }

    loadLogs()
  }, [selectedSeasonId])

  const seasonOptions = useMemo(
    () =>
      seasons.map((season) => ({
        id: season.season_id,
        label: `${season.season_name || `MÃ¹a vá»¥ ${season.season_id}`} - Ao ${season.pond_id}`,
      })),
    [seasons]
  )

  const handleChange = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }))
  }

  const handleSubmit = async (event) => {
    event.preventDefault()

    try {
      setSaving(true)
      setError('')
      setSuccess('')

      await cultivationLogService.createLog({
        seasonId: Number(form.seasonId),
